import React from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const normalizedCondition = condition.toLowerCase();
  if (normalizedCondition.includes('sunny') || normalizedCondition.includes('clear')) return '☀️';
  if (normalizedCondition.includes('cloudy') || normalizedCondition.includes('cloud')) return '☁️';
  if (normalizedCondition.includes('rainy') || normalizedCondition.includes('rain')) return '🌧️';
  if (normalizedCondition.includes('snow')) return '❄️';
  if (normalizedCondition.includes('wind')) return '💨';
  if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist')) return '🌫️';
  if (normalizedCondition.includes('thunder') || normalizedCondition.includes('storm')) return '⛈️';
  return '🌤️';
};

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit,
    forecast = [],
  } = props;

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      style={{
        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with City */}
        <Text variant="h2" color="var(--ggui-color-primary-900, #0c4a6e)" weight="bold">
          {city}
        </Text>

        {/* Current Weather Section */}
        <Stack direction="horizontal" gap={16} align="center">
          {/* Weather Emoji/Icon */}
          <div
            style={{
              fontSize: '72px',
              lineHeight: '1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            {weatherEmoji}
          </div>

          {/* Temperature and Condition */}
          <Stack direction="vertical" gap={8}>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-900, #0c4a6e)',
                lineHeight: '1',
              }}
            >
              {temperature}°{unit}
            </div>
            <Text
              variant="body"
              color="var(--ggui-color-primary-700, #0369a1)"
              weight="medium"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Weather Details Grid */}
        <Stack direction="horizontal" gap={16} justify="between">
          {/* Humidity */}
          <div
            style={{
              padding: 'var(--ggui-spacing-4, 16px)',
              backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              flex: 1,
              textAlign: 'center',
            }}
          >
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" weight="medium">
              Humidity
            </Text>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-xl, 20px)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                color: 'var(--ggui-color-primary-900, #0c4a6e)',
                marginTop: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {humidity}%
            </div>
          </div>

          {/* Wind Speed */}
          <div
            style={{
              padding: 'var(--ggui-spacing-4, 16px)',
