              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              flex: 1,
              textAlign: 'center',
            }}
          >
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" weight="medium">
              Wind Speed
            </Text>
            <div
              style={{
                fontSize: 'var(--ggui-font-size-xl, 20px)',
