                    {day.high}°
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-sm, 14px)',
                      fontWeight: 'var(--ggui-font-weight-normal, 400)',
                      color: 'var(--ggui-color-neutral-500, #6b7280)',
                    }}
                  >
                    {day.low}°
                  </span>
                </div>
              </div>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
