            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import { useState } from 'react';
import { Card, Stack, Row, Text, Divider } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 65,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '☁️', high: 73, low: 60 },
    { day: 'Wed', icon: '🌧️', high: 68, low: 58 },
    { day: 'Thu', icon: '☀️', high: 74, low: 61 },
    { day: 'Fri', icon: '☀️', high: 76, low: 63 },
  ],
}: Props) {
  // Get weather emoji based on condition
  const getWeatherEmoji = (cond: string): string => {
    const condLower = cond.toLowerCase();
    if (condLower.includes('sunny') || condLower.includes('clear')) return '☀️';
    if (condLower.includes('cloudy') || condLower.includes('overcast')) return '☁️';
    if (condLower.includes('rainy') || condLower.includes('rain')) return '🌧️';
    if (condLower.includes('snow')) return '❄️';
    if (condLower.includes('wind')) return '💨';
    if (condLower.includes('storm') || condLower.includes('thunder')) return '⛈️';
    if (condLower.includes('fog') || condLower.includes('mist')) return '🌫️';
    return '🌤️'; // Default partly cloudy
  };

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card padding={0} shadow="sm" border={false}>
      <Stack direction="vertical" gap={0}>
        {/* Main weather section */}
        <div
          style={{
            background: 'linear-gradient(135deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-700, #0369a1))',
            padding: 'var(--ggui-spacing-6, 24px)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) 0 0',
          }}
        >
          <Stack direction="vertical" gap={8}>
            {/* City and condition header */}
            <Row justify="between" align="center">
              <Text variant="h3" weight="bold" color="var(--ggui-color-neutral-50, #f9fafb)">
                {city}
              </Text>
              <span style={{ fontSize: '32px' }}>{weatherEmoji}</span>
            </Row>

            {/* Temperature - large and prominent */}
            <div
              style={{
                display: 'flex',
                alignItems: 'baseline',
                gap: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              <span
                style={{
                  fontSize: 'var(--ggui-font-size-4xl, 36px)',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-neutral-50, #f9fafb)',
                  lineHeight: '1',
                }}
              >
                {temperature}
              </span>
              <span
                style={{
                  fontSize: 'var(--ggui-font-size-2xl, 24px)',
                  fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                  color: 'var(--ggui-color-neutral-50, #f9fafb)',
                }}
              >
                {unit}
              </span>
            </div>

            {/* Weather condition description */}
            <Text variant="body" color="var(--ggui-color-primary-100, #e0f2fe)" weight="medium">
              {condition}
            </Text>
          </Stack>
        </div>

        {/* Details section - humidity and wind speed */}
        <div
          style={{
            background: 'var(--ggui-color-neutral-50, #f9fafb)',
            padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
          }}
        >
          <Row justify="around" align="center">
            {/* Humidity */}
            <Stack direction="vertical" align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                Humidity
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                {humidity}%
              </Text>
            </Stack>

            {/* Wind speed */}
            <Stack direction="vertical" align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                Wind Speed
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">
                {windSpeed} mph
              </Text>
            </Stack>
          </Row>
        </div>

        {/* 5-day forecast strip */}
        <div
          style={{
            background: 'var(--ggui-color-neutral-50, #f9fafb)',
            padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
            borderRadius: '0 0 var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)',
            borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
          }}
        >
          <Stack direction="vertical" gap={12}>
            <Text
              variant="label"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="semibold"
            >
              5-Day Forecast
            </Text>

            {/* Forecast items in horizontal scroll strip */}
            <Row gap={8} wrap={false}>
              {forecast.map((day, idx) => (
                <div
                  key={idx}
                  style={{
                    flex: '0 0 auto',
                    background: 'var(--ggui-color-neutral-100, #f3f4f6)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)',
                    textAlign: 'center',
                    minWidth: '70px',
                    border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                  }}
                >
                  <Stack direction="vertical" align="center" gap={4}>
                    {/* Day name */}
                    <Text
                      variant="caption"
                      weight="semibold"
                      color="var(--ggui-color-neutral-700, #374151)"
                    >
                      {day.day}
                    </Text>

                    {/* Weather icon */}
                    <span style={{ fontSize: '20px' }}>{day.icon}</span>

                    {/* High/Low temps */}
                    <div
                      style={{
                        display: 'flex',
                        gap: 'var(--ggui-spacing-1, 4px)',
                        justifyContent: 'center',
                        fontSize: 'var(--ggui-font-size-xs, 12px)',
                      }}
                    >
                      <span
                        style={{
                          fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                          color: 'var(--ggui-color-neutral-900, #111827)',
                        }}
                      >
                        {day.high}°
                      </span>
                      <span style={{ color: 'var(--ggui-color-neutral-500, #6b7280)' }}>
                        {day.low}°
                      </span>
                    </div>
                  </Stack>
                </div>
              ))}
            </Row>
          </Stack>
        </div>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Row, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();
  if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
  if (lowerCondition.includes('cloudy') || lowerCondition.includes('cloud')) return '☁️';
  if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
  if (lowerCondition.includes('snow')) return '❄️';
  if (lowerCondition.includes('storm') || lowerCondition.includes('thunder')) return '⛈️';
  if (lowerCondition.includes('wind')) return '💨';
  if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';
  return '🌤️';
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Box
      style={{
        width: '100vw',
        height: '100dvh',
