// Helper function to map condition strings to emojis
function getWeatherEmoji(condition: string): string {
  const lower = condition.toLowerCase();

  if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloudy') || lower.includes('overcast')) return '☁️';
  if (lower.includes('rainy') || lower.includes('rain')) return '🌧️';
  if (lower.includes('thunderstorm') || lower.includes('storm')) return '⛈️';
  if (lower.includes('snowy') || lower.includes('snow')) return '❄️';
  if (lower.includes('windy') || lower.includes('wind')) return '💨';
  if (lower.includes('fog') || lower.includes('misty')) return '🌫️';
  if (lower.includes('partly')) return '⛅';

  return '🌤️'; // Default
}

