const getWeatherEmoji = (condition: string): string => {
  const normalizedCondition = condition.toLowerCase().trim();
  const emojiMap: Record<string, string> = {
    sunny: '☀️',
    clear: '🌟',
    cloudy: '☁️',
    rainy: '🌧️',
    rain: '🌧️',
    snowy: '❄️',
    snow: '❄️',
    stormy: '⛈️',
    storm: '⛈️',
    thunderstorm: '⛈️',
    'partly_cloudy': '⛅',
    'partly cloudy': '⛅',
    'partlycloudy': '⛅',
    windy: '💨',
    wind: '💨',
    foggy: '🌫️',
    fog: '🌫️',
    hazy: '🌫️',
    drizzle: '🌦️',
    sleet: '🌨️',
  };
  return emojiMap[normalizedCondition] || '🌤️'; // Default to partly cloudy
};

