  windSpeed: number;
  unit: string;
  forecast: ForecastItem[];
}

/**
 * WeatherCard component displays current weather information and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 10,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 60 },
    { day: 'Tue', icon: '⛅', high: 72, low: 58 },
    { day: 'Wed', icon: '☁️', high: 68, low: 55 },
    { day: 'Thu', icon: '🌧️', high: 65, low: 52 },
    { day: 'Fri', icon: '☀️', high: 70, low: 57 },
  ],
}: Props) {
  // Helper to map condition string to an emoji if needed
  const getConditionIcon = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('shower')) return '🌧️';
    if (c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '⛅';
  };

  return (
    <Card padding={24} shadow="md">
      <Stack gap={24}>
        {/* Header: City and Date */}
        <Row justify="between" align="start">
          <Stack gap={4}>
            <Text variant="h2" weight="bold">
              {city}
            </Text>
            <Text variant="body" color="var(--ggui-color-neutral-500)">
              {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
            </Text>
          </Stack>
          <Box style={{ fontSize: '3rem' }}>
            {getConditionIcon(condition)}
          </Box>
        </Row>

        {/* Current Temperature and Condition */}
        <Row align="center" gap={16}>
          <Text 
            style={{ 
              fontSize: 'var(--ggui-font-size-4xl)', 
              fontWeight: 'var(--ggui-font-weight-bold)',
              color: 'var(--ggui-color-neutral-900)'
            }}
          >
            {Math.round(temperature)}{unit}
          </Text>
          <Stack gap={0}>
            <Text variant="h3" weight="semibold">
              {condition}
            </Text>
            <Text variant="caption" color="var(--ggui-color-neutral-500)">
              Feels like {Math.round(temperature - 2)}{unit}
            </Text>
          </Stack>
        </Row>

        {/* Secondary Stats */}
        <Row gap={32}>
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-neutral-500)">Humidity</Text>
            <Text weight="medium">{humidity}%</Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-neutral-500)">Wind Speed</Text>
            <Text weight="medium">{windSpeed} mph</Text>
          </Stack>
        </Row>

        <Divider margin={8} />

        {/* Forecast Strip */}
        <Row justify="between" gap={12} wrap>
          {forecast.map((item, index) => (
            <Stack 
              key={index} 
              align="center" 
              gap={8} 
              style={{ 
                flex: '1 1 0px',
                minWidth: '60px',
                padding: 'var(--ggui-spacing-2)',
                borderRadius: 'var(--ggui-shape-radius-md)',
                background: index === 0 ? 'var(--ggui-color-primary-50)' : 'transparent',
                border: index === 0 ? '1px solid var(--ggui-color-primary-100)' : '1px solid transparent'
              }}
            >
              <Text variant="caption" weight="semibold" color="var(--ggui-color-neutral-500)">
                {item.day}
              </Text>
              <Box style={{ fontSize: '1.5rem' }}>
                {item.icon}
              </Box>
              <Stack gap={0} align="center">
                <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-sm)' }}>
                  {Math.round(item.high)}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500)">
                  {Math.round(item.low)}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Card>
  );
}
